/* insertGoodLifeMemberMst2 */
INSERT INTO MSP_GOODLIFE_MEMBER_MST (
	CONTRACT_NUM
	, SVC_CNTR_NO
	, END_DTTM
	, STRT_DTTM
	, CUSTOMER_ID
	, SUBSCRIBER_NO
	, MINOR_AGENT_NM
	, MINOR_AGENT_TEL
	, RATE_CD
	, RMK
	, DC_CNT
	, REGST_ID
	, REGST_DTTM
)
SELECT  #{contractNum, jdbcType=VARCHAR}
        , #{svcCntrNo, jdbcType=VARCHAR}
        , '99991231235959'
        , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
        , #{customerId, jdbcType=VARCHAR}
        , #{subscriberNo, jdbcType=VARCHAR}
        , #{minorAgentNm, jdbcType=VARCHAR}
        , #{minorAgentTel, jdbcType=VARCHAR}
        , #{rateCd, jdbcType=VARCHAR}
        , #{rmk, jdbcType=VARCHAR}
        , MAX(NVL(DC_CNT, 0)) OVER(PARTITION BY CUSTOMER_ID)
        , 'BATCH'
        , SYSDATE
FROM    MSP_GOODLIFE_MEMBER_MST
WHERE   CUSTOMER_ID = #{customerId, jdbcType=VARCHAR}
AND     ROWNUM = 1

