/* goodlifeMapper.insertGoodlifeInterface */
INSERT INTO MSP_PARTNER_GOODLIFE_01
(
	 IF_NO				/* 인터페이스ID */
	,IF_YMD				/* 연동일자 or 월 */
	,SVC_CNTR_NO		/* 서비스계약번호 */
	,SUBSCRIBER_NO		/* 전화번호 */
	,PARTNER_YN			/* 상조상품가입여부 */
	,PARTNER_PYMN_YN	/* 상조상품수납여부 */
	,GOODLIFE_ID		/* 상조ID */
	,PAY_CNT			/* 좋은상조수납차수 */
	,USG_YM				/* 사용월 */
	,BILL_YM			/* 청구월 */
	,STTL_YM			/* 정산월 */
	,DC_AMT				/* 엠모바일할인금액 */
	,CB_AMT				/* 좋은상조할인금액 */
	,DC_CNT				/* 엠모바일할인차수 */
	,REGST_DTTM			/* 등록일시 */
)
VALUES 
(
	 #{ifNo}
	,#{ifYmd}
	,#{svcCntrNo}
	,#{ctn}
	,#{statYn}
	,#{pymnYn}
	,#{goodlifeId}
	,#{payCnt}
	,#{usgYm}
	,#{billYm}
	,#{sttlYm}
	,#{dcAmt}
	,#{cbAmt}
	,#{dcCnt}
	,SYSDATE
)

